INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-57f41407-moex-00496', 'disabled-57f41407', 'disabled-57f41407-moex-111-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '「這樣不推銷的推銷術，在這裡最合適。有些店舖，主顧上門，不但不著 急兜攬生意，而且於客氣之中寓有生疏之意。例如書店，進得店門，四壁 圖書雖然塞得滿滿的，但盡是些普通書籍，你若問他有什麼好書，他說沒 有什麼，你說隨便看看，他說請看請看。結果是你什麼好書也看不見，但 是你若去過幾次，做成幾回生意，情形就不同了，他會請你到裡櫃坐，再 過些時請到後櫃坐，升堂入室之後，箱子裡的好書善本陸陸續續的都拿出 來了。宋版的，元槧的，琳琅滿目，還小聲的囑咐你，不要對外人說，生 意之外，還套著交情。」下列選項，何者最能形容文中的推銷術？', '["深藏若虛", "虛懷若谷", "明褒暗貶", "循循善誘"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:37+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00497', 'disabled-57f41407', 'disabled-57f41407-moex-111-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '「總是嚮往一處可以憩息的地方，好讓你卸下肩頭的重擔，有人叫著你的 名字，像百年榕樹永遠認得飄零的葉子。啊，家的感覺或許很簡單，不管 飄盪多少年，衣衫如何襤褸，老宅旁邊榕蔭下，有一塊石墩讓你小坐，下 弈的老人數算將士兵馬，還不忘告訴你，這兒有冰鎮的麥茶。沒有人攻訐 你的過往，古井流水依然清澈，你可以洗癒炎涼江湖烙在身上的傷疤，你 無需在惡意的詆毀中像奔逃的小鹿，亦不必沈溺於浮名如迷途的羔羊，你 只是一個願意關愛他人也被呵護著的人，你是春雀的同伴，流雲的知己。 月亮照耀青窗，窗裡窗外皆有青色的光。不管遠方如何聲討你是背信的人， 月光下總有一扇青窗，堅持說你是唯一被等待的人。」根據上文，下列選 項何者最符合作者意旨？', '["人生如逆旅，我們不斷飄盪在這處那處之間", "家鄉永遠只存留在模糊的記憶之中供人憑弔", "純樸而溫厚的鄉村是旅遊與休閒的最佳去處", "家鄉永遠敞開溫暖雙臂迎接漂泊的遊子歸來"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:37+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00498', 'disabled-57f41407', 'disabled-57f41407-moex-111-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '「望著海洋一陣的強風帶給海面一大片的灰暗，景象帶來淒涼的落寂感， 洞裡的青煙使我想到拓拔斯（布農族）的小說《最後的獵人》裡的男主角 比雅日和妻子帕蘇拉的故事。帕蘇拉對比雅日說：『……如果你聽我的話 到平地做臨時綑工，買幾件毛衣就不需為冷天劈柴烤火取暖……。』但比 雅日終究沒有去平地做綑工，反而上山去打獵；因為只有在深山才覺得有 尊嚴，有智慧，真正展露布農男人的氣魄。雖然在回部落途中他的獵物被 檢查哨的惡警擄走，僅留給他一隻狐狸孝敬帕蘇拉。比雅日無膽怨嘆，只 覺得惡質剝削在越為複雜的社會裡如鬼魂般地經常的，自然的落在弱勢、 窮人的命運裡。」下列選項，最符合本文旨意的是：', '["以客觀的角度分析原住民族文化在現實社會中的優勢與劣勢", "即使生活受到壓迫，仍無法取代原住民族對自身文化的熱愛", "認為原住民族文化是其唯一的依歸，只有與外界阻隔才能保留", "作者對於原住民族文化的關懷，盼望政府能給予原住民族工作機會"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:37+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00499', 'disabled-57f41407', 'disabled-57f41407-moex-111-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '繪本《活了一百萬次的貓》作者佐野洋子面對癌轉移的任性態度，堪稱經 典。洋子只問醫師兩個問題：「還有幾年？」「到死之前要花多少錢？」 確定錢都夠花，立刻決定：「請不要延長我的壽命。」然後在回家路上， 走進名車代理店，指著英格蘭綠的積架說：「買了。」「得知還有兩年可 活，折磨了我數十年的憂鬱症也好了！」她說知道自己的死期，也得到了 自由。佐野洋子真是神奇歐巴桑。看來，自知死之將至，也沒什麼不好， 重要的是我們能不能有足夠的自由，選擇走到生命末日的方式。根據上文， 下列選項最接近作者人生旨趣的是：', '["反對佐野洋子癌症轉移後放棄治療", "人自知死亡之將至有益治療憂鬱症", "只要財力足夠就可以安享生命末期", "人即使到生命末期也要能自主安頓"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:37+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00500', 'disabled-57f41407', 'disabled-57f41407-moex-111-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '「有一個『雁行理論』說，當雁鼓動雙翼時，對尾隨的同伴具有『鼓舞』 的作用，雁群一字排開成V字型時，比孤雁單飛增加了七成的飛行距離。 一般來說，不論何時，當一隻雁脫離隊伍，牠馬上會感受到一股動力阻止 牠離開，藉著前一隻夥伴的『支撐力』，牠很快便能回到隊伍。此外，在 一個雁陣中，當帶頭的雁疲倦了，牠會退回隊伍，由另一隻取代牠的位置。 同時，在雁陣隊伍中後面的雁，會以叫聲鼓勵前面的夥伴繼續前進；當有 雁隻生病或受傷時，其他兩隻會由隊伍飛下來協助及保護牠，這兩隻雁便 一直陪伴牠到康復或死亡為止，然後牠們自己組成隊伍再開始飛行，或者 去追趕上原來的雁群。」根據上文「雁行理論」所帶給人們的啟示，下列 選項何者錯誤？', '["留在與自己目標一致的隊伍，並且樂意接受他人的協助，便能使團隊邁 向成功之路", "與擁有相同目標的人同行，因著彼此之間的互相推動，便能快速、容易 地到達目的地", "為避免拖累團隊達標進展，就算眼前困難重重，也要抱著捨我其誰的精 神，繼續拼搏", "適時給予團隊夥伴讚美與鼓勵，能使團隊挺過艱難的時刻、有動力持續 努力並達成目標"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:37+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00501', 'disabled-57f41407', 'disabled-57f41407-moex-111-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '「在我們空前焦慮自己是個沒故事、沒身世、沒歷史的——民族？島嶼？ 國家？——的此時此際，難道我們甘心注定永遠是個樹小牆新、沒有積累、 沒有記憶，因此對這個地方也沒有什麼不可讓渡的感情的民族？島嶼？國 家？格雷安．葛林在《哈瓦那特派員》寫過：『人口研究報告可以印出各 種統計數值、城市人口，藉以描繪一個城市。但對城裡的每個人而言，所 謂城市不過是幾條巷道、幾間房子和幾個人的組合，沒有了這些，一個城 市形同隕落，只剩下悲涼的記憶，那種痛苦就像失去了一條腿般的空虛。』 說得真好，不是嗎？」根據上文，下列選項何者錯誤？', '["城市的故事來自於人與環境的組合", "沒有身世的城市無法累積認同的情感", "人口研究報告可具體看出城市發展軌跡", "城市沒有自己的歷史可能使居民感到焦慮"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:37+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00502', 'disabled-57f41407', 'disabled-57f41407-moex-111-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於民事訴訟之合意管轄，下列敘述何者正確？', '["當事人不得合意定第二審之管轄法院", "當事人得就雙方間不特定之一切民事法律關係定合意管轄法院", "當事人得以合意管轄之約定，變更專屬管轄之法院", "原告向有管轄權之法院起訴後，於第一審程序中，得以合意定第一審管 轄法院"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "768f62303fcf", "answer_pdf_sha1": "d7be33bb3a54", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0408", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00503', 'disabled-57f41407', 'disabled-57f41407-moex-111-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', 'A 主張 B 於臺灣臺北地方法院大門前出言辱罵 A，侵害 A 之名譽權，向 臺灣臺北地方法院起訴請求損害賠償，經分由該法院法官甲獨任審理。關 於法官迴避，下列敘述何者正確？', '["A為甲之前配偶，因原有婚姻關係已消滅，非屬甲應自行迴避事由", "甲見聞 A及 B之爭吵過程，雖未到場作證陳述，仍為本件訴訟之潛在 證人，屬甲應自行迴避事由", "B 為甲親姐之配偶之父，因 B 為甲三親等內之姻親，屬甲應自行迴避 事由", "甲於轉任法官前執行律師業務，曾於另案為 A 之訴訟代理人，非屬甲 應自行迴避事由"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "768f62303fcf", "answer_pdf_sha1": "d7be33bb3a54", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0408", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00504', 'disabled-57f41407', 'disabled-57f41407-moex-111-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', 'A公益社團法人章程係以協助職業傷害勞工為宗旨，A之社員甲、乙、丙 先前均任職丁公司，甲、乙、丙主張在丁公司任職期間，因丁公司管理不 當，其等受有健康權、身體權之損害。甲、乙、丙選定A為被選定人，起 訴請求丁公司賠償損害，嗣甲於訴訟進行中死亡，下列敘述何者錯誤？', '["在甲之繼承人聲明承受訴訟前，訴訟程序當然停止", "A為被選定人之資格，不因甲死亡而受影響", "甲之全體繼承人得撤回選定", "該訴訟如判決確定，對甲之繼承人亦有效力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "768f62303fcf", "answer_pdf_sha1": "d7be33bb3a54", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0408", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00505', 'disabled-57f41407', 'disabled-57f41407-moex-111-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '依民事訴訟法規定，下列何者非屬無訴訟能力人？', '["受輔助宣告之人", "18歲未婚之人", "受監護宣告之人", "未滿7歲之人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "768f62303fcf", "answer_pdf_sha1": "d7be33bb3a54", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0408", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL)
